//! The monster guard stack, wired into the rogue.
//!
//! Before badchild lets an `Allow` reach a real moonshine session, the session
//! must be cost-admitted against the AntColony FRF budget (monster-swarm) and
//! will be launched under a monster-guard lease. The two binary-only crates in
//! the family (monster-guard, moonshine) are reached the way monster-swarm
//! already reaches them: by shelling out via `monster_swarm::guard`. That live
//! containment is the gateway layer; here we wire the *admission* decision,
//! which is pure and linkable.
//!
//! Graceful degradation closes the loop on the persona: if the budget denies a
//! real session, the `Allow` does not fail - it degrades to a shadow redirect.
//! Everyone still gets through; they just (again) do not go where they want.

use monster_swarm::budget::{Admission, Caste, FleetBudget, FleetProfile};

/// The result of trying to admit a real moonshine session for an allowed caller.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum SessionAdmission {
    /// A real session is affordable; carry the stability weight forward.
    Admitted { stability_weight: u32 },
    /// The budget is exhausted; the caller must be degraded to shadow instead.
    Degrade { reason: String },
}

impl SessionAdmission {
    pub fn is_admitted(&self) -> bool {
        matches!(self, SessionAdmission::Admitted { .. })
    }
}

/// Cost-admit a real moonshine session against the FRF budget. A new session is
/// a `Scout` spawn (an outward-facing worker), consistent with monster-swarm's
/// caste model.
pub fn admit_session(budget: &FleetBudget, current: &FleetProfile) -> SessionAdmission {
    match budget.admit_spawn(current, Caste::Scout) {
        Admission::Admit { stability_weight } => SessionAdmission::Admitted { stability_weight },
        Admission::Deny(reason) => SessionAdmission::Degrade { reason },
    }
}

/// The lease the contained moonshine child would run under. Mirrors monster-guard's
/// `LeaseConfig` shape; the gateway hands these to `monster_swarm::guard` /
/// `monster-guard run` when it actually spawns the child.
#[derive(Debug, Clone, Copy)]
pub struct LeasePlan {
    pub ttl_secs: u64,
    pub renew_at_secs: u64,
    pub hard_ceiling_secs: u64,
    pub kill_grace_secs: u64,
}

impl Default for LeasePlan {
    fn default() -> Self {
        LeasePlan {
            ttl_secs: 30,
            renew_at_secs: 10,
            hard_ceiling_secs: 300,
            kill_grace_secs: 5,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn budget() -> FleetBudget {
        FleetBudget {
            population_ceiling: 10,
            min_breeders: 1,
        }
    }

    #[test]
    fn admits_a_session_under_ceiling() {
        let current = FleetProfile {
            breeders: 1,
            reproductive_void: 0,
            scouts: 0,
            vent_burden: 0,
        };
        assert!(admit_session(&budget(), &current).is_admitted());
    }

    #[test]
    fn degrades_when_budget_exhausted() {
        // At the population ceiling, a new scout cannot be admitted.
        let current = FleetProfile {
            breeders: 5,
            reproductive_void: 0,
            scouts: 5,
            vent_burden: 0,
        };
        let a = admit_session(&budget(), &current);
        assert!(!a.is_admitted(), "ceiling reached -> degrade to shadow");
        assert!(matches!(a, SessionAdmission::Degrade { .. }));
    }
}
